-- migration_v32_ziraat_kesin_dokum.sql
-- Kaynak: HESAP HAR. HK.xlsx (T.C. Ziraat Bankası — Döşemealti/Antalya Şubesi)
-- Dönem: 2025-05-15 → 2025-12-30 | 256 işlem | 39 günlük bakiye snapshot
-- Hesap adı: Ziraat Kesin Döküm (kayıtlarda source_account ve account_daily_balance)

DO $$
DECLARE
  cid UUID;
BEGIN
  SELECT company_id INTO cid FROM founding_cashflow LIMIT 1;
  IF cid IS NULL THEN RAISE EXCEPTION 'founding_cashflow bos - once Parasut senkronizasyonu yapin'; END IF;

  -- KISIM 1: Hareket kayıtları (founding_cashflow)

  -- KISIM 2: Günlük bakiye snapshots (account_daily_balance — Banka Nakdi Günlük grafik için)
  ON CONFLICT (company_id, account_name, tarih) DO UPDATE SET bakiye = EXCLUDED.bakiye;

  RAISE NOTICE '% hareket + % günlük bakiye eklendi (Ziraat Kesin Döküm)', 256, 39;
END $$;
